            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-3 flex items-center gap-2">
              <ListPlus size={16} className="text-indigo-400" /> Parlay Size: {maxLegs} Legs
            </label>
            <input 
              type="range" min="2" max="12" value={maxLegs} 
              onChange={(e) => setMaxLegs(parseInt(e.target.value))}
              className="w-full h-2 bg-slate-700 rounded-lg accent-indigo-500 mt-4"
            />
            <div className="flex justify-between text-[10px] text-slate-500 mt-2 px-1">
              <span>2 (Safe)</span>
              <span>12 (Risky)</span>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-3 flex items-center gap-2">
