import { GoogleGenAI } from "@google/genai";
import { MatchData, ParlayRecommendation, UserSettings, BacktestResult, StrategyPlan, StrategyStep, GroundingSource, BacktestTrade } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const cleanJson = (text: string) => {
  if (!text) return "[]";
  let clean = text.replace(/```json\s*/g, "").replace(/```\s*/g, "");
  const firstCurly = clean.indexOf('{');
  const lastCurly = clean.lastIndexOf('}');
  const firstSquare = clean.indexOf('[');
  const lastSquare = clean.lastIndexOf(']');
  if (firstCurly !== -1 && (firstSquare === -1 || firstCurly < firstSquare)) {
    return clean.substring(firstCurly, lastCurly + 1);
  } else if (firstSquare !== -1) {
    return clean.substring(firstSquare, lastSquare + 1);
  }
  return clean.trim();
};

const extractSources = (response: any): GroundingSource[] => {
  const sources: GroundingSource[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks && Array.isArray(chunks)) {
    chunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({ title: chunk.web.title || "Source", uri: chunk.web.uri });
      }
    });
  }
  return sources.filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i);
};

const SYSTEM_PROMPT = `You are a high-precision Football Quantitative Analyst. Today's date is ${new Date().toISOString().split('T')[0]}.
Your primary directives are MATHEMATICAL ACCURACY and DATA GROUNDING.
- Use real-world search data for match outcomes and odds.
- For all-in compounding strategies, the stake of step N is the total return of step N-1.
- You must calculate P/L as: Stake * (Odds - 1).
- You must calculate Balance After as: Stake * Odds.
- One loss = $0 balance and sequence termination.`;

export const getMarketSummary = async (settings: UserSettings): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `${SYSTEM_PROMPT}\nSummarize the football market for ${settings.targetDate} in 2 sentences focusing on why banker opportunities might be scarce.`,
      config: { tools: [{ googleSearch: {} }] },
    });
    return response.text || "Market intelligence recalibrating.";
  } catch (e) {
    return "Market analysis temporarily limited.";
  }
};

export const fetchUpcomingMatches = async (settings: UserSettings): Promise<{ matches: MatchData[], rawContext: string, sources: GroundingSource[] }> => {
  try {
    const leagues = settings.isGlobalScan ? "all major professional leagues globally" : settings.selectedLeagues.join(', ');
    const prompt = `${SYSTEM_PROMPT}\nSearch for at least 20-30 REAL football fixtures occurring on ${settings.targetDate}. 
    Focus on ${leagues}. 
    Return a comprehensive report on these matches including teams, competition, and early market sentiment.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }], thinkingConfig: { thinkingBudget: 20000 } },
    });

    const sources = extractSources(response);
    const rawText = response.text || "";

    const formatPrompt = `From the following context: "${rawText}", extract as many fixtures as possible into a JSON array of MatchData objects. Include the competition, home team, away team, and date.`;
    const formatResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: formatPrompt,
      config: { responseMimeType: 'application/json' }
    });

    const parsed = JSON.parse(cleanJson(formatResponse.text || "[]"));
    return { matches: Array.isArray(parsed) ? parsed : [], rawContext: rawText, sources };
  } catch (error) {
    throw new Error("Match data synchronization failed.");
  }
};

export const analyzeAndGenerateParlays = async (matchesContext: string, settings: UserSettings): Promise<ParlayRecommendation[]> => {
  try {
    const prompt = `${SYSTEM_PROMPT}\nUsing the match data found: ${matchesContext}\n
    Construct 3 separate high-probability ${settings.maxLegs}-leg parlays.
    Target total odds around ${settings.targetOdds}.
    Each parlay must contain exactly ${settings.maxLegs} selections.
    Provide a detailed reasoning for each leg. 
    Return a JSON array of ParlayRecommendation objects.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }], thinkingConfig: { thinkingBudget: 24000 }, responseMimeType: 'application/json' },
    });

    const sources = extractSources(response);
    let parsed = JSON.parse(cleanJson(response.text || "[]"));
    if (!Array.isArray(parsed)) parsed = [parsed];

    return parsed.map((p: any) => ({
      ...p,
      legs: p.legs || [],
      totalOdds: parseFloat(p.totalOdds) || settings.targetOdds,
      recommendedStake: settings.bankroll,
      stakePercentage: 100,
      confidenceScore: p.confidenceScore || 8,
      sources
    }));
  } catch (error) {
    return [];
  }
};

export const generateStrategyPlan = async (settings: UserSettings, matchesContext: string): Promise<StrategyPlan> => {
  try {
    const prompt = `${SYSTEM_PROMPT}\nCreate a "Strategic Roadmap" starting $${settings.bankroll} to $${settings.targetBankroll} at ${settings.targetOdds} odds. 
    Construct a step-by-step compounding path. For the first few steps, use real matches from: ${matchesContext}. JSON format.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }], thinkingConfig: { thinkingBudget: 24000 }, responseMimeType: 'application/json' },
    });
    const result = JSON.parse(cleanJson(response.text || "{}"));
    const totalSteps = result.totalSteps || Math.ceil(Math.log(settings.targetBankroll / settings.bankroll) / Math.log(settings.targetOdds));

    return {
      ...result,
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      targetOdds: settings.targetOdds,
      totalSteps: totalSteps,
      sources: extractSources(response),
      steps: Array.isArray(result.steps) && result.steps.length > 0 ? result.steps : generateFallbackSteps(settings, totalSteps)
    };
  } catch (e) {
    const fallbackSteps = Math.ceil(Math.log(settings.targetBankroll / settings.bankroll) / Math.log(settings.targetOdds));
    return {
      createdAt: new Date().toISOString(),
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      targetOdds: settings.targetOdds,
      totalSteps: fallbackSteps,
      analysis: "Projecting theoretical path.",
      steps: generateFallbackSteps(settings, fallbackSteps)
    };
  }
};

function generateFallbackSteps(settings: UserSettings, count: number): StrategyStep[] {
  const steps: StrategyStep[] = [];
  let currentStake = settings.bankroll;
  for (let i = 1; i <= count; i++) {
    const win = currentStake * settings.targetOdds;
    steps.push({
      stepNumber: i,
      date: `Window ${i}`,
      plannedStake: currentStake,
      projectedWin: win,
      status: i === 1 ? 'ready' : 'pending_previous_win',
      note: `Compound target: ${settings.targetOdds} odds.`
    });
    currentStake = win;
  }
  return steps;
}

export const performBacktest = async (settings: UserSettings): Promise<BacktestResult> => {
  const start = settings.backtestDate || settings.targetDate;
  const prompt = `
    ${SYSTEM_PROMPT}
    Perform Grounded Backtest. Starting: $${settings.bankroll} | Goal: $${settings.targetBankroll} | Target Odds: ${settings.targetOdds}.
    Reference Date: ${start}.
    1. Search REAL matches on/after ${start}.
    2. Simulate an ALL-IN compounding ladder. Stake N = Balance After N-1.
    3. Each step should be a ${settings.maxLegs}-leg parlay.
    4. Calculate P/L and Balance After for every trade.
    5. Provide JSON with 'trades' array.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: { tools: [{ googleSearch: {} }], thinkingConfig: { thinkingBudget: 32768 }, responseMimeType: 'application/json' },
  });

  const sources = extractSources(response);
  try {
    const result = JSON.parse(cleanJson(response.text || "{}"));
    const rawTrades = Array.isArray(result.trades) ? result.trades : [];

    let currentBalance = settings.bankroll;
    const repairedTrades: BacktestTrade[] = rawTrades.map((trade: any) => {
      const stake = currentBalance;
      const odds = trade.odds || settings.targetOdds;
      const result = trade.result || 'WIN';

      let pnl = 0;
      let bankrollAfter = 0;

      if (result === 'WIN') {
        pnl = stake * (odds - 1);
        bankrollAfter = stake * odds;
        currentBalance = bankrollAfter;
      } else {
        pnl = -stake;
        bankrollAfter = 0;
        currentBalance = 0;
      }

      return {
        ...trade,
        stake,
        odds,
        pnl,
        bankrollAfter
      };
    });

    return {
      ...result,
      period: start,
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      finalBankroll: currentBalance,
      sources,
      trades: repairedTrades
    };
  } catch (e) {
    return {
      period: start,
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      finalBankroll: settings.bankroll,
      totalTrades: 0,
      wins: 0,
      losses: 0,
      roi: 0,
      trades: [],
      analysis: "Grounded simulation failed to resolve."
    };
  }
};

export const generateBetslipOfTheWeek = analyzeAndGenerateParlays;
export const generateOneShotParlay = analyzeAndGenerateParlays;
export const generateCorrectScoreTips = analyzeAndGenerateParlays;
export const performOneShotBacktest = performBacktest;

import React, { useState } from 'react';
import { AppState, UserSettings, MatchData, ParlayRecommendation, BacktestResult, StrategyPlan, GroundingSource } from './types';
import { SetupForm } from './components/SetupForm';
import { ParlayCard } from './components/ParlayCard';
import { BacktestDashboard } from './components/BacktestDashboard';
import { StrategyDashboard } from './components/StrategyDashboard';
import { LoadingScreen } from './components/LoadingScreen';
import { fetchUpcomingMatches, analyzeAndGenerateParlays, performBacktest, generateStrategyPlan, generateBetslipOfTheWeek, generateOneShotParlay, performOneShotBacktest, generateCorrectScoreTips, getMarketSummary } from './services/geminiService';
import { ShieldAlert, Settings2, Globe, Zap, Coffee, Info, ExternalLink, List, ChevronDown, ChevronUp } from 'lucide-react';

export default function App() {
  const [state, setState] = useState<AppState>('setup');
  const [settings, setSettings] = useState<UserSettings | null>(null);
  const [matches, setMatches] = useState<MatchData[]>([]);
  const [parlays, setParlays] = useState<ParlayRecommendation[]>([]);
  const [backtestResults, setBacktestResults] = useState<BacktestResult | null>(null);
  const [strategyPlan, setStrategyPlan] = useState<StrategyPlan | null>(null);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [scoutAdvice, setScoutAdvice] = useState<string | null>(null);
  const [showScannedMatches, setShowScannedMatches] = useState(false);

  const handleSetupComplete = async (userSettings: UserSettings) => {
    setSettings(userSettings);
    setError(null);
    setScoutAdvice(null);
    setSources([]);
    setShowScannedMatches(false);

    try {
      if (userSettings.analysisMode === 'live' || 
          userSettings.analysisMode === 'betslip_of_the_week' || 
          userSettings.analysisMode === 'one_shot_challenge' || 
          userSettings.analysisMode === 'correct_score') {

        setState('searching');
        const { matches: foundMatches, rawContext, sources: foundSources } = await fetchUpcomingMatches(userSettings);
        setMatches(foundMatches);
        setSources(foundSources);

        if (!foundMatches || foundMatches.length === 0) {
          const advice = await getMarketSummary(userSettings);
          setScoutAdvice(advice);
          setState('error');
          return;
        }

        setState('analyzing');
        let recommendations: ParlayRecommendation[] = [];

        switch(userSettings.analysisMode) {
          case 'live': recommendations = await analyzeAndGenerateParlays(rawContext, userSettings); break;
          case 'betslip_of_the_week': recommendations = await generateBetslipOfTheWeek(rawContext, userSettings); break;
          case 'one_shot_challenge': recommendations = await generateOneShotParlay(rawContext, userSettings); break;
          case 'correct_score': recommendations = await generateCorrectScoreTips(rawContext, userSettings); break;
        }

        if (recommendations.length === 0) {
          const advice = await getMarketSummary(userSettings);
          setScoutAdvice(advice);
          setState('error');
          return;
        }

        setParlays(recommendations);
        setState('results');

      } else if (userSettings.analysisMode === 'strategy_prep') {
        setState('searching'); 
        const { matches: foundMatches, rawContext } = await fetchUpcomingMatches(userSettings);
        setMatches(foundMatches);
        setState('analyzing');
        const plan = await generateStrategyPlan(userSettings, rawContext);
        setStrategyPlan(plan);
        setState('strategy_results');

      } else {
        setState('backtesting');
        const results = userSettings.analysisMode === 'one_shot_backtest' 
          ? await performOneShotBacktest(userSettings)
          : await performBacktest(userSettings);
        setBacktestResults(results);
        setState('backtest_results');
      }

    } catch (err) {
      setError("The AI data synchronization failed. This usually happens when search databases are down or the date is invalid.");
      setState('error');
    }
  };

  const handleReset = () => {
    setState('setup');
    setSettings(null);
    setMatches([]);
    setParlays([]);
    setBacktestResults(null);
    setStrategyPlan(null);
    setScoutAdvice(null);
    setSources([]);
  };

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col">
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-50 backdrop-blur-md bg-opacity-80">
        <div className="max-w-7xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-lg shadow-indigo-500/20">
              <Globe className="text-white" size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-white tracking-tight">SmartBet Analytics</h1>
              <span className="text-xs text-indigo-400 font-mono uppercase tracking-widest">Grounded Pro Engine</span>
            </div>
          </div>
          {(state !== 'setup' && state !== 'searching' && state !== 'analyzing' && state !== 'backtesting') && (
            <button onClick={handleReset} className="flex items-center gap-2 text-sm text-slate-400 hover:text-white transition-colors bg-slate-800 px-3 py-1.5 rounded-lg border border-slate-700">
              <Settings2 size={16} /> Configuration
