    };
  } catch (e) {
    const fallbackSteps = 10;
    return {
      createdAt: new Date().toISOString(),
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      targetOdds: 1.5,
      totalSteps: fallbackSteps,
      analysis: "Projecting safety path.",
      steps: generateFallbackSteps(settings, fallbackSteps)
    };
  }
};

function generateFallbackSteps(settings: UserSettings, count: number): StrategyStep[] {
  const steps: StrategyStep[] = [];
  const safeOdds = 1.5;
  let currentStake = settings.bankroll;
  for (let i = 1; i <= count; i++) {
    const win = currentStake * safeOdds;
    steps.push({
      stepNumber: i,
      date: `Window ${i}`,
      plannedStake: currentStake,
      projectedWin: win,
      status: i === 1 ? 'ready' : 'pending_previous_win',
      note: `Targeting 1.5 odds banker for max safety.`
    });
    currentStake = win;
  }
  return steps;
}

export const performBacktest = async (settings: UserSettings): Promise<BacktestResult> => {
  const start = settings.backtestDate || settings.targetDate;
  const prompt = `
    ${SYSTEM_PROMPT}
    Perform Grounded Backtest on SAFEST Banker picks. 
    Reference Date: ${start}.
    Simulate an ALL-IN sequence using only the absolute most certain outcomes found in search.
    Sequence should use 2-leg parlays of around 1.4-1.8 total odds.
    Provide JSON with 'trades' array.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: { tools: [{ googleSearch: {} }], thinkingConfig: { thinkingBudget: 32768 }, responseMimeType: 'application/json' },
  });

  const sources = extractSources(response);
  try {
    const result = JSON.parse(cleanJson(response.text || "{}"));
    const rawTrades = Array.isArray(result.trades) ? result.trades : [];

    let currentBalance = settings.bankroll;
    const repairedTrades: BacktestTrade[] = rawTrades.map((trade: any) => {
      const stake = currentBalance;
      const odds = trade.odds || 1.6;
      const result = trade.result || 'WIN';

      let pnl = 0;
      let bankrollAfter = 0;

      if (result === 'WIN') {
        pnl = stake * (odds - 1);
        bankrollAfter = stake * odds;
        currentBalance = bankrollAfter;
      } else {
        pnl = -stake;
        bankrollAfter = 0;
        currentBalance = 0;
      }

      return {
        ...trade,
        stake,
        odds,
        pnl,
        bankrollAfter
      };
    });

    return {
      ...result,
      period: start,
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      finalBankroll: currentBalance,
      sources,
      trades: repairedTrades
    };
  } catch (e) {
    return {
      period: start,
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      finalBankroll: settings.bankroll,
      totalTrades: 0,
      wins: 0,
      losses: 0,
      roi: 0,
      trades: [],
      analysis: "Grounded simulation failed."
    };
  }
};

