        bankrollAfter = 0;
        currentBalance = 0;
      }

      return {
        ...trade,
        stake,
        odds,
        pnl,
        bankrollAfter
      };
    });

    return {
      ...result,
      period: start,
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      finalBankroll: currentBalance,
      sources,
      trades: repairedTrades
    };
  } catch (e) {
    return {
      period: start,
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      finalBankroll: settings.bankroll,
      totalTrades: 0,
      wins: 0,
      losses: 0,
      roi: 0,
      trades: [],
      analysis: "Grounded simulation failed."
    };
  }
};

