        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              riskLevel: { type: Type.STRING },
              totalOdds: { type: Type.NUMBER },
